#!/usr/bin/env python

import os
import sys
import time
import tarfile
import zipfile
import subprocess
import shutil
from datetime import datetime

def create_backup(source_dir, output_format='tar.gz', output_dir=None):
    if not os.path.exists(source_dir):
        print("Error: Source directory does not exist: {}".format(source_dir))
        return False
    
    if not os.path.isdir(source_dir):
        print("Error: Source path is not a directory: {}".format(source_dir))
        return False
    
    source_dir = os.path.abspath(source_dir)
    dir_name = os.path.basename(source_dir.rstrip(os.sep))
    timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    
    if output_dir is None:
        output_dir = os.path.dirname(source_dir)
    else:
        output_dir = os.path.abspath(output_dir)
        if not os.path.exists(output_dir):
            os.makedirs(output_dir)
    
    output_format = output_format.lower()
    
    if output_format == 'tar.gz' or output_format == 'tgz':
        archive_name = '{}_backup_{}.tar.gz'.format(dir_name, timestamp)
        archive_path = os.path.join(output_dir, archive_name)
        return create_tar_backup(source_dir, archive_path, 'gz')
    
    elif output_format == 'tar.bz2' or output_format == 'tbz2':
        archive_name = '{}_backup_{}.tar.bz2'.format(dir_name, timestamp)
        archive_path = os.path.join(output_dir, archive_name)
        return create_tar_backup(source_dir, archive_path, 'bz2')
    
    elif output_format == 'tar':
        archive_name = '{}_backup_{}.tar'.format(dir_name, timestamp)
        archive_path = os.path.join(output_dir, archive_name)
        return create_tar_backup(source_dir, archive_path, None)
    
    elif output_format == 'zip':
        archive_name = '{}_backup_{}.zip'.format(dir_name, timestamp)
        archive_path = os.path.join(output_dir, archive_name)
        return create_zip_backup(source_dir, archive_path)
    
    elif output_format == '7z':
        archive_name = '{}_backup_{}.7z'.format(dir_name, timestamp)
        archive_path = os.path.join(output_dir, archive_name)
        return create_7z_backup(source_dir, archive_path)
    
    else:
        print("Error: Unsupported format: {}".format(output_format))
        print("Supported formats: tar.gz, tar.bz2, tar, zip, 7z")
        return False

def create_tar_backup(source_dir, archive_path, compression):
    try:
        print("Creating tar backup: {}".format(archive_path))
        
        if compression == 'gz':
            mode = 'w:gz'
        elif compression == 'bz2':
            mode = 'w:bz2'
        else:
            mode = 'w'
        
        with tarfile.open(archive_path, mode) as tar:
            parent_dir = os.path.dirname(source_dir)
            base_name = os.path.basename(source_dir)
            
            os.chdir(parent_dir)
            tar.add(base_name, recursive=True)
        
        print("Backup created successfully: {}".format(archive_path))
        print_file_size(archive_path)
        return True
    
    except Exception as e:
        print("Error creating tar backup: {}".format(str(e)))
        return False

def create_zip_backup(source_dir, archive_path):
    try:
        print("Creating zip backup: {}".format(archive_path))
        
        with zipfile.ZipFile(archive_path, 'w', zipfile.ZIP_DEFLATED) as zipf:
            parent_dir = os.path.dirname(source_dir)
            base_name = os.path.basename(source_dir)
            
            for root, dirs, files in os.walk(source_dir):
                for file in files:
                    file_path = os.path.join(root, file)
                    arcname = os.path.join(base_name, os.path.relpath(file_path, source_dir))
                    zipf.write(file_path, arcname)
        
        print("Backup created successfully: {}".format(archive_path))
        print_file_size(archive_path)
        return True
    
    except Exception as e:
        print("Error creating zip backup: {}".format(str(e)))
        return False

def create_7z_backup(source_dir, archive_path):
    try:
        if not shutil.which('7z') and not shutil.which('7za'):
            if not os.path.exists('/usr/bin/7z') and not os.path.exists('/usr/bin/7za'):
                print("Error: 7z is not installed on this system")
                return False
        
        print("Creating 7z backup: {}".format(archive_path))
        
        cmd_7z = '7z'
        if shutil.which('7za') or os.path.exists('/usr/bin/7za'):
            cmd_7z = '7za'
        
        parent_dir = os.path.dirname(source_dir)
        base_name = os.path.basename(source_dir)
        
        cmd = [cmd_7z, 'a', '-t7z', archive_path, base_name]
        
        process = subprocess.Popen(cmd, cwd=parent_dir, stdout=subprocess.PIPE, stderr=subprocess.PIPE)
        stdout, stderr = process.communicate()
        
        if process.returncode == 0:
            print("Backup created successfully: {}".format(archive_path))
            print_file_size(archive_path)
            return True
        else:
            print("Error creating 7z backup:")
            if stderr:
                print(stderr.decode('utf-8', errors='ignore'))
            return False
    
    except Exception as e:
        print("Error creating 7z backup: {}".format(str(e)))
        return False

def print_file_size(file_path):
    try:
        size_bytes = os.path.getsize(file_path)
        if size_bytes < 1024:
            print("Archive size: {} bytes".format(size_bytes))
        elif size_bytes < 1024 * 1024:
            print("Archive size: {:.2f} KB".format(size_bytes / 1024.0))
        elif size_bytes < 1024 * 1024 * 1024:
            print("Archive size: {:.2f} MB".format(size_bytes / (1024.0 * 1024.0)))
        else:
            print("Archive size: {:.2f} GB".format(size_bytes / (1024.0 * 1024.0 * 1024.0)))
    except:
        pass

